    print(f"Error logs ({log_results['total']} total):")
    for log in log_results["logs"]:
        print(f"  [{log['level']}] {log['service']}: {log['message']}")

    print("\n--- Search Logs by Service ---")
    log_results = log_mgr.search_logs(service="api-gateway", size=5)
    print(f"API Gateway logs ({log_results['total']} total):")
    for log in log_results["logs"]:
        print(f"  [{log['level']}] {log['message']}")

    # 6. Log aggregations
    print("\n--- Log Aggregations ---")
