    for service, count in sorted(service_counts.items()):
        print(f"  {service}: {count}")

    print("\nService health summary:")
    health_summary = aggregator.service_health_summary(hours=24)
    for service, stats in health_summary.items():
        print(f"  {service}: {stats['health']} "
              f"(total: {stats['total_logs']}, error_rate: {stats['error_rate']}%)")

    # 7. Python logging integration
