    # Flush the handler to ensure all logs are sent
    es_handler.flush()

    # Cleanup
    print("\n--- Cleanup ---")
    platform.index_manager.delete_index("articles")
    platform.index_manager.delete_index(log_index)
    print("Cleaned up demo indices")

    print("\n" + "=" * 70)
    print("Demo completed successfully!")
    print("=" * 70)


